mapper.select:
SELECT ID id, CREATE_DATE createDate, UPDATE_DATE updateDate, DELETE_YN deleteYn, STOCK_ID stockId, NAME name, PRICE price, PRICE_BEFOREDAY priceBeforeday, FACE_VALUE faceValue, MARKET_CAPITALIZATION marketCapitalization, STOCK_QTY stockQty, FOREIGNER_RATIO foreignerRatio, VOLUMN volumn, PER per, ESTIMATION_PER estimationPer, ROE roe, PBR pbr, BPS bps, INDUSTRY_PER industryPer, INDUSTRY_BAISSE industryBaisse, INVESTMENT_OPINION investmentOpinion, TARGET_PRICE targetPrice, MAX_52 max52, MIN_52 min52, DIVIDEND_RATE dividendRate, NATIONAL national FROM ST_STOCK_MASTER M
AND M.DELETE_YN = 'N'
AND M.ID = #{id}
AND M.STOCK_ID = #{stockId}

SELECT ID id, CREATE_DATE createDate, UPDATE_DATE updateDate, DELETE_YN deleteYn, TOTAL_SALES totalSales, PROFITS profits, EARNINGS earnings, PROFITS_RATIO profitsRatio, NET_PROFIT_RATIO netProfitRatio, ROE roe, DEPT_RATIO deptRatio, RESERVE_RATIO reserveRatio, EPS eps, PER per, BPS bps, PBR pbr, DIVIDENDS_PER_SHARE dividendsPerShare, DIVIDENDS_RATE dividendsRate, DIVIDENDS_TENDENCY dividendsTendency, YEAR year, STOCK_ID stockId, STOCK_MASTER_ID stockMasterId, SHARES_OUTSTANDING sharesOutstanding, TOTAL_ASSETS totalAssets, TOTAL_DEPT totalDept, TOTAL_CAPITAL totalCapital, CAPITAL capital FROM ST_STOCK_FINANCIAL F
AND F.DELETE_YN = 'N'
AND F.YEAR = #{year}
AND F.STOCK_ID = #{stockId}

SELECT I.STOCK_DIVISION stockDivision , IFNULL(I.STOCK_TYPE, '주식') stockType , IFNULL(M.NAME, I.STOCK_ID) name , I.STOCK_ID stockId , I.STOCK_QTY qty , IFNULL(M.PRICE, 0) * I.STOCK_QTY totalPrice , ROUND(P.STANDARD_PRICE * I.STOCK_POTION) standard , ROUND(P.STANDARD_PRICE * I.STOCK_POTION) - IFNULL(M.PRICE, 0) * I.STOCK_QTY addPrice , I.STOCK_POTION stockPotion , IFNULL(M.PRICE, 0) price , IFNULL(M.MAX_52, 0) max52 , IFNULL(M.MIN_52, 0) min52 , CASE WHEN IFNULL(M.MAX_52, 0) > 0 THEN ROUND((CAST(M.MAX_52 AS SIGNED) - CAST(IFNULL(M.PRICE, 0) AS SIGNED)) * 100.0 / M.MAX_52, 2) ELSE NULL END rate52 , CASE WHEN IFNULL(M.MAX_52, 0) > IFNULL(M.MIN_52, 0) THEN LEAST(100, GREATEST(0, ROUND((IFNULL(M.PRICE,0) - IFNULL(M.MIN_52,0)) * 100.0 / (IFNULL(M.MAX_52,0) - IFNULL(M.MIN_52,0)), 1))) ELSE NULL END pos52 , CASE WHEN SUM(IFNULL(M.PRICE, 0) * I.STOCK_QTY) OVER (PARTITION BY I.STOCK_DIVISION) > 0 THEN ROUND(IFNULL(M.PRICE, 0) * I.STOCK_QTY * 100.0 / SUM(IFNULL(M.PRICE, 0) * I.STOCK_QTY) OVER (PARTITION BY I.STOCK_DIVISION), 2) ELSE 0 END actualPotion , RANK() OVER(PARTITION BY I.STOCK_DIVISION ORDER BY (ROUND(P.STANDARD_PRICE * I.STOCK_POTION) - IFNULL(M.PRICE, 0) * I.STOCK_QTY) DESC) rk , NULL month1Rate , NULL month3Rate , NULL month6Rate , NULL month12Rate FROM ST_STOCK_INTEREST I INNER JOIN ST_STOCK_INTEREST_PARAM P ON P.STOCK_DIVISION = I.STOCK_DIVISION LEFT JOIN ST_STOCK_MASTER M ON M.STOCK_ID = I.STOCK_ID
AND I.STOCK_DIVISION = #{stockDivision}
ORDER BY P.ORDER_NUM, I.STOCK_DIVISION, (ROUND(P.STANDARD_PRICE * I.STOCK_POTION) - IFNULL(M.PRICE, 0) * I.STOCK_QTY) DESC

SELECT I.STOCK_ID stockId , I.STOCK_DIVISION stockDivision , I.STOCK_QTY qty , I.STOCK_POTION stockPotion , IFNULL(M.NAME, I.STOCK_ID) name , IFNULL(M.PRICE, 0) * I.STOCK_QTY totalPrice FROM ST_STOCK_INTEREST I LEFT JOIN ST_STOCK_MASTER M ON M.STOCK_ID = I.STOCK_ID
AND I.STOCK_DIVISION = #{stockDivision}
ORDER BY I.STOCK_DIVISION, I.STOCK_POTION DESC

mapper.update:
UPDATE ST_STOCK_MASTER
SET INDUSTRY_PER = #{industryPer}, UPDATE_DATE = NOW()
WHERE STOCK_ID = #{stockId}

mapper.select:
SELECT R.* FROM ( SELECT T.stockId, T.name, T.price, T.marketCapitalization, T.industryPer, T.currentPer, T.currentPbr, T.currentRoe, T.currentDividendRate, T.currentDebtRatio, T.dividendTendency, T.avgPer3y, T.avgRoe3y, T.roePassYears, T.divPayYears, T.divConsecutive, T.profitConsecutive, T.currentRatio, T.operatingCashFlow, T.valueUpYn, T.industryPerRatio, T.max52, T.min52, T.sectorName, ( CASE WHEN T.currentPer > 0 AND T.currentPer <= #{filterPerMax} THEN 1 ELSE 0 END + CASE WHEN T.currentPbr > 0 AND T.currentPbr <= #{filterPbrMax} THEN 1 ELSE 0 END + CASE WHEN T.avgRoe3y >= #{filterRoeMin} AND T.roePassYears >= 3 THEN 1 ELSE 0 END + CASE WHEN T.currentDividendRate >= #{filterDividendMin} OR T.dividendTendency >= 25 THEN 1 ELSE 0 END + CASE WHEN T.currentDebtRatio >= 0 AND T.currentDebtRatio <= #{filterDebtMax} THEN 1 ELSE 0 END + CASE WHEN T.divConsecutive >= 3 THEN 1 ELSE 0 END + CASE WHEN T.profitConsecutive >= 3 THEN 1 ELSE 0 END + CASE WHEN T.currentRatio >= 100 THEN 1 ELSE 0 END + CASE WHEN T.operatingCashFlow > 0 THEN 1 ELSE 0 END + CASE WHEN T.valueUpYn = 'Y' THEN 1 ELSE 0 END ) AS passCount, 10 AS totalCriteria FROM ( SELECT M.STOCK_ID stockId, M.NAME name, M.PRICE price, M.MARKET_CAPITALIZATION marketCapitalization, M.INDUSTRY_PER industryPer, CAST(NULLIF(M.PER, '') AS DECIMAL(10,2)) currentPer, CAST(NULLIF(M.PBR, '') AS DECIMAL(10,2)) currentPbr, CAST(NULLIF(M.ROE, '') AS DECIMAL(10,2)) currentRoe, CAST(NULLIF(M.DIVIDEND_RATE, '') AS DECIMAL(10,2)) currentDividendRate, IFNULL(FL.latestDebtRatio, -1) currentDebtRatio, IFNULL(FL.latestDivTendency, 0) dividendTendency, FA.avgPer3y, FA.avgRoe3y, IFNULL(FA.roePassYears, 0) roePassYears, IFNULL(FD.divPayYears, 0) divPayYears, IFNULL(FD.divConsecutive, 0) divConsecutive, IFNULL(FD.profitConsecutive, 0) profitConsecutive, IFNULL(FL.currentRatio, -1) currentRatio, IFNULL(FL.operatingCashFlow, 0) operatingCashFlow, IFNULL(M.VALUE_UP_YN, 'N') valueUpYn, CASE WHEN CAST(NULLIF(M.INDUSTRY_PER, '') AS DECIMAL(10,2)) > 0 THEN ROUND(CAST(NULLIF(M.PER, '') AS DECIMAL(10,2)) / CAST(NULLIF(M.INDUSTRY_PER, '') AS DECIMAL(10,2)) * 100, 1) ELSE NULL END industryPerRatio, M.MAX_52 max52, M.MIN_52 min52, (SELECT C.CATEGORY_NAME FROM ST_STOCK_CATEGORY_LINK CL JOIN ST_STOCK_CATEGORY C ON C.CATEGORY_NO = CL.CATEGORY_NO AND C.CATEGORY_TYPE = 'industry' WHERE CL.STOCK_ID = M.STOCK_ID LIMIT 1) sectorName FROM ST_STOCK_MASTER M LEFT JOIN ( SELECT F.STOCK_ID, CAST(NULLIF(F.DEPT_RATIO, '') AS DECIMAL(10,2)) latestDebtRatio, CASE WHEN F.DIVIDENDS_TENDENCY IS NOT NULL AND F.DIVIDENDS_TENDENCY > 0 THEN CAST(F.DIVIDENDS_TENDENCY AS DECIMAL(10,2)) WHEN F.DIVIDENDS_PER_SHARE > 0 AND F.EPS > 0 THEN ROUND(F.DIVIDENDS_PER_SHARE / F.EPS * 100, 2) ELSE 0 END latestDivTendency, CASE WHEN CAST(NULLIF(F.LIQUID_ASSET, '') AS DECIMAL(20,2)) > 0 AND CAST(NULLIF(F.LIQUID_DEPT, '') AS DECIMAL(20,2)) > 0 THEN ROUND(CAST(NULLIF(F.LIQUID_ASSET, '') AS DECIMAL(20,2)) / CAST(NULLIF(F.LIQUID_DEPT, '') AS DECIMAL(20,2)) * 100, 1) ELSE -1 END currentRatio, IFNULL(CAST(NULLIF(F.OPERATING_CASH_FLOW, '') AS DECIMAL(20,2)), 0) operatingCashFlow FROM ST_STOCK_FINANCIAL F INNER JOIN ( SELECT STOCK_ID, MAX(YEAR) maxYear FROM ST_STOCK_FINANCIAL WHERE DELETE_YN = 'N' AND YEAR < YEAR(CURDATE()) GROUP BY STOCK_ID ) lat ON F.STOCK_ID = lat.STOCK_ID AND F.YEAR = lat.maxYear WHERE F.DELETE_YN = 'N' ) FL ON FL.STOCK_ID = M.STOCK_ID LEFT JOIN ( SELECT ranked.STOCK_ID, ROUND(AVG(ranked.perVal), 2) avgPer3y, ROUND(AVG(ranked.roeVal), 2) avgRoe3y, SUM(CASE WHEN ranked.roeVal >= #{filterRoeMin} THEN 1 ELSE 0 END) roePassYears FROM ( SELECT F2.STOCK_ID, F2.YEAR, CAST(NULLIF(F2.PER, '') AS DECIMAL(10,2)) perVal, CAST(NULLIF(F2.ROE, '') AS DECIMAL(10,2)) roeVal, ROW_NUMBER() OVER (PARTITION BY F2.STOCK_ID ORDER BY F2.YEAR DESC) rn FROM ST_STOCK_FINANCIAL F2 WHERE F2.DELETE_YN = 'N' AND F2.YEAR < YEAR(CURDATE()) ) ranked WHERE ranked.rn <= 3 GROUP BY ranked.STOCK_ID ) FA ON FA.STOCK_ID = M.STOCK_ID LEFT JOIN ( SELECT r5.STOCK_ID, SUM(CASE WHEN r5.dps > 0 THEN 1 ELSE 0 END) divPayYears, LEAST(MIN(CASE WHEN r5.dps <= 0 THEN r5.rn ELSE 6 END) - 1, 5) divConsecutive, LEAST(MIN(CASE WHEN r5.profit <= 0 THEN r5.rn ELSE 6 END) - 1, 5) profitConsecutive FROM ( SELECT F3.STOCK_ID, IFNULL(F3.DIVIDENDS_PER_SHARE, 0) dps, IFNULL(CAST(NULLIF(F3.PROFITS, '') AS DECIMAL(20,2)), 0) profit, ROW_NUMBER() OVER (PARTITION BY F3.STOCK_ID ORDER BY F3.YEAR DESC) rn FROM ST_STOCK_FINANCIAL F3 WHERE F3.DELETE_YN = 'N' AND F3.YEAR < YEAR(CURDATE()) ) r5 WHERE r5.rn <= 5 GROUP BY r5.STOCK_ID ) FD ON FD.STOCK_ID = M.STOCK_ID WHERE M.DELETE_YN = 'N' AND M.PER IS NOT NULL AND M.PER != '' AND M.PER != '0' AND M.PBR IS NOT NULL AND M.PBR != '' AND M.PBR != '0' ) T ) R WHERE R.passCount >= #{filterPassCountMin}
AND CAST(R.marketCapitalization AS UNSIGNED) >= #{filterMarketCapMin}
ORDER BY R.passCount DESC, R.currentPer ASC
